def calculate_bakers_percentages(ingredients, flour_weight):
    bakers_percentages = {}
    for ingredient, weight in ingredients.items():
        percentage = (weight / flour_weight) * 100
        bakers_percentages[ingredient] = percentage
    return bakers_percentages

# Example usage:
ingredients = {'flour': 500, 'water': 300, 'salt': 10}
flour_weight = ingredients['flour']
percentages = calculate_bakers_percentages(ingredients, flour_weight)
print(percentages)
# Output: {'flour': 100.0, 'water': 60.0, 'salt': 2.0}
